export const rnRespRenalFlashcardsBatch2: FlashcardData[] = [
  // ============================================================
  // PULMONARY HYPERTENSION (15 more = 25 total)
  // ============================================================
  { id: "rn-ph-11", type: "question", question: "What is the WHO classification system for pulmonary hypertension?", options: ["2 groups based on severity", "5 groups based on etiology and mechanism", "3 groups based on treatment response", "4 groups based on age of onset"], correctIndex: 1, answer: "WHO classifies PH into 5 groups: Group 1 (PAH), Group 2 (left heart disease), Group 3 (lung disease/hypoxia), Group 4 (chronic thromboembolic), Group 5 (multifactorial/unclear mechanisms).", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-12", type: "question", question: "Treprostinil (Remodulin) can be administered by all EXCEPT which route?", options: ["Subcutaneous infusion", "Intravenous infusion", "Inhaled (Tyvaso)", "Intramuscular injection"], correctIndex: 3, answer: "Treprostinil is available SC, IV, inhaled (Tyvaso), and oral (Orenitram). IM injection is NOT an available route. The SC route is most common but causes significant injection site pain.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-13", type: "question", question: "What lab value should be monitored in PAH patients to assess right heart failure severity?", options: ["Troponin I", "BNP/NT-proBNP", "D-dimer", "CRP"], correctIndex: 1, answer: "BNP/NT-proBNP reflects right ventricular strain and volume overload. Rising levels correlate with worsening RV function and poorer prognosis in PAH.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-14", type: "question", question: "Cor pulmonale in PAH refers to:", options: ["Left ventricular failure from pulmonary disease", "Right ventricular hypertrophy and failure from pulmonary hypertension", "Biventricular failure", "Atrial septal defect"], correctIndex: 1, answer: "Cor pulmonale is right heart failure secondary to pulmonary disease. The RV hypertrophies to overcome increased PVR but eventually dilates and fails, causing JVD, hepatomegaly, and peripheral edema.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-15", type: "question", question: "A V/Q scan is preferred over CTPA for suspected chronic thromboembolic PH because:", options: ["It is cheaper", "It is more sensitive for chronic organized thrombi in CTEPH", "It avoids radiation", "It is faster to perform"], correctIndex: 1, answer: "V/Q scanning is more sensitive than CTPA for detecting chronic thromboembolic PH (Group 4) because organized thrombi in CTEPH can line vessel walls and be missed by CTPA.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ph-16", type: "question", question: "What percentage of PAH patients respond to calcium channel blockers?", options: ["50%", "75%", "About 10% (only those with positive vasoreactivity test)", "All PAH patients"], correctIndex: 2, answer: "Only approximately 10% of PAH patients have a positive vasoreactivity test and respond to CCBs. The vast majority require PAH-specific therapy (ERAs, PDE5 inhibitors, prostacyclins).", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-17", type: "question", question: "Epoprostenol requires reconstitution and ice packing because:", options: ["It tastes better cold", "It is thermally unstable with a short shelf life at room temperature", "Ice prevents infection", "It must be frozen before use"], correctIndex: 1, answer: "Epoprostenol is chemically unstable at room temperature and must be kept on ice. It requires reconstitution every 8-12 hours. Newer thermostable formulations have extended this but still require careful handling.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ph-18", type: "question", question: "Which connective tissue disease is MOST commonly associated with PAH?", options: ["Rheumatoid arthritis", "Scleroderma (systemic sclerosis)", "Osteoarthritis", "Gout"], correctIndex: 1, answer: "Scleroderma (systemic sclerosis) is the connective tissue disease most commonly associated with PAH. Up to 12% of scleroderma patients develop PAH. Regular screening with echocardiography is recommended.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-19", type: "question", question: "What drug exposure is most strongly linked to development of PAH?", options: ["Acetaminophen", "Methamphetamine and appetite suppressants (fenfluramine)", "Ibuprofen", "Penicillin"], correctIndex: 1, answer: "Methamphetamine and appetite suppressants like fenfluramine are strongly linked to PAH development. Meth causes pulmonary vascular remodeling. Drug screening is part of PAH workup.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-20", type: "question", question: "The BMPR2 gene mutation is associated with:", options: ["Cystic fibrosis", "Heritable pulmonary arterial hypertension", "Sickle cell disease", "Alpha-1 antitrypsin deficiency"], correctIndex: 1, answer: "BMPR2 (bone morphogenetic protein receptor type 2) mutations are found in ~70% of heritable PAH and ~25% of idiopathic PAH cases. Genetic counseling is appropriate for affected families.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ph-21", type: "question", question: "Sildenafil for PAH differs from its use for erectile dysfunction in that:", options: ["The dose is higher for PAH", "The dose is lower for PAH (20mg TID vs 50-100mg PRN)", "It is given IV for PAH", "There is no difference"], correctIndex: 1, answer: "PAH dosing: 20mg TID (3 times daily). ED dosing: 50-100mg PRN. The PAH dose is significantly lower but given regularly. Do not confuse the two indications.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-22", type: "question", question: "What physical exam finding indicates RV pressure overload?", options: ["Left-sided S3 gallop", "Parasternal lift (RV heave)", "Mitral valve click", "Aortic regurgitation murmur"], correctIndex: 1, answer: "A parasternal lift or RV heave (palpable impulse at the left sternal border) indicates RV hypertrophy from pressure overload. This finding, along with loud P2, suggests pulmonary hypertension.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-23", type: "question", question: "What activity should PAH patients be counseled to avoid?", options: ["Walking on flat ground", "Isometric exercise (heavy lifting, straining)", "Reading", "Light swimming"], correctIndex: 1, answer: "Isometric exercises like heavy lifting cause Valsalva maneuver, which dramatically increases intrathoracic pressure, reduces venous return, and can cause syncope or death in PAH. Graded aerobic exercise is safer.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ph-24", type: "question", question: "Supplemental oxygen in PAH is used to maintain SpO2 above:", options: ["85%", "90% (preventing hypoxic pulmonary vasoconstriction)", "95%", "98%"], correctIndex: 1, answer: "Supplemental O2 targets SpO2 >90% to prevent hypoxic pulmonary vasoconstriction (HPV), which would further increase pulmonary vascular resistance and worsen PH.", category: "Respiratory", difficulty: 1 },
  { id: "rn-ph-25", type: "question", question: "A 6-minute walk distance less than what value indicates poor prognosis in PAH?", options: ["500 meters", "400 meters", "300 meters", "200 meters"], correctIndex: 2, answer: "6MWD <300 meters is associated with poor prognosis in PAH and indicates severe functional limitation. It is the most commonly used functional endpoint in PAH clinical trials.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // ARDS (15 more = 25 total)
  // ============================================================
  { id: "rn-ards-11", type: "question", question: "What causes surfactant deficiency in ARDS?", options: ["Increased surfactant production", "Damage to type II pneumocytes that produce surfactant", "Excessive surfactant breakdown only", "Genetic surfactant deficiency"], correctIndex: 1, answer: "Type II pneumocytes produce surfactant. In ARDS, these cells are damaged by the inflammatory cascade, leading to surfactant deficiency, increased surface tension, and alveolar collapse (atelectasis).", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-12", type: "question", question: "The three phases of ARDS pathology in order are:", options: ["Fibrotic, proliferative, exudative", "Exudative (days 1-7), proliferative (days 7-21), fibrotic (after day 21)", "Inflammatory, resolution, chronic", "Acute, subacute, chronic"], correctIndex: 1, answer: "ARDS phases: (1) Exudative (1-7 days): inflammation, hyaline membranes, edema; (2) Proliferative (7-21 days): type II pneumocyte proliferation, fibroblast activity; (3) Fibrotic (>21 days): irreversible fibrosis in some patients.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-13", type: "question", question: "Why is PEEP used in ARDS management?", options: ["To increase tidal volume", "To recruit collapsed alveoli and improve oxygenation by preventing end-expiratory alveolar collapse", "To decrease respiratory rate", "To reduce cardiac output"], correctIndex: 1, answer: "PEEP maintains positive pressure at end-expiration, preventing alveolar collapse and recruiting previously atelectatic alveoli. This improves functional residual capacity and V/Q matching.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-14", type: "question", question: "The PROSEVA trial demonstrated mortality benefit of prone positioning in ARDS patients with:", options: ["Mild ARDS (P/F 200-300)", "Moderate-severe ARDS (P/F <150) when prone for 12-16 hours/day", "All ARDS patients", "Only post-surgical ARDS"], correctIndex: 1, answer: "PROSEVA showed significant mortality reduction with prone positioning >=16 hours/day in early moderate-severe ARDS (P/F <150). It improves V/Q matching by redistributing perfusion to better-ventilated lung.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-15", type: "question", question: "What nursing intervention prevents VAP in an intubated ARDS patient?", options: ["Suctioning every hour routinely", "Oral care with chlorhexidine every 2 hours and HOB 30-45 degrees", "Prone positioning only", "Keeping the cuff deflated"], correctIndex: 1, answer: "VAP prevention bundle includes: oral care with chlorhexidine q2h, HOB 30-45 degrees, daily sedation vacation and spontaneous breathing trials, DVT and PUD prophylaxis.", category: "Respiratory", difficulty: 1 },
  { id: "rn-ards-16", type: "question", question: "TRALI (transfusion-related acute lung injury) is caused by:", options: ["Volume overload from transfusion", "Donor antibodies activating recipient neutrophils in the pulmonary vasculature", "ABO incompatibility", "Bacterial contamination of blood"], correctIndex: 1, answer: "TRALI results from donor antibodies (anti-HLA or anti-neutrophil) that activate recipient neutrophils in the pulmonary vasculature, causing capillary leak and non-cardiogenic pulmonary edema resembling ARDS.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-17", type: "question", question: "Train-of-four monitoring is used for patients on:", options: ["Propofol sedation", "Neuromuscular blocking agents (cisatracurium) - target 1-2 twitches of 4", "Fentanyl infusion", "Midazolam drip"], correctIndex: 1, answer: "Train-of-four (TOF) monitors the degree of neuromuscular blockade by electrically stimulating a peripheral nerve. Target 1-2 twitches out of 4 ensures adequate paralysis without overdosing.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-18", type: "question", question: "Propofol infusion syndrome occurs with:", options: ["Short-term use at standard doses", "Prolonged high-dose infusion (>5 mg/kg/hr for >48 hours)", "Oral administration", "Low-dose sedation"], correctIndex: 1, answer: "Propofol infusion syndrome: metabolic acidosis, rhabdomyolysis, cardiac failure with prolonged high-dose use. Monitor triglycerides every 48-72h. Limit dose and duration when possible.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-19", type: "question", question: "When should ECMO be considered for ARDS?", options: ["As first-line treatment", "For refractory hypoxemia despite maximum conventional therapy (prone, NMB, high PEEP)", "For all moderate ARDS", "Only for pediatric patients"], correctIndex: 1, answer: "ECMO (extracorporeal membrane oxygenation) is a rescue therapy for severe ARDS with refractory hypoxemia despite maximum conventional therapy including lung-protective ventilation, prone positioning, and neuromuscular blockade.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-20", type: "question", question: "Fat embolism syndrome following a long bone fracture can cause ARDS. Classic findings include:", options: ["Hematemesis and melena", "Petechial rash, neurological changes, and respiratory distress 24-72 hours after fracture", "Isolated joint pain", "Urticaria and angioedema"], correctIndex: 1, answer: "Fat embolism syndrome: fat globules enter circulation from fractured bone marrow. Classic triad: petechial rash (chest, axilla, conjunctivae), neurological changes (confusion), and respiratory distress 24-72 hours post-fracture.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-21", type: "question", question: "Why is fentanyl preferred over morphine in hemodynamically unstable ARDS patients?", options: ["Fentanyl is cheaper", "Fentanyl causes no histamine release (less hypotension) unlike morphine", "Fentanyl has a longer duration", "Morphine cannot be given IV"], correctIndex: 1, answer: "Morphine causes histamine release leading to vasodilation and hypotension. Fentanyl does not release histamine, making it preferred in hemodynamically unstable patients (sepsis, shock, ARDS).", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-22", type: "question", question: "What is driving pressure in ARDS ventilation?", options: ["Peak inspiratory pressure", "Plateau pressure minus PEEP - reflects the actual distending pressure of the alveoli", "PEEP alone", "Mean airway pressure"], correctIndex: 1, answer: "Driving pressure = plateau pressure - PEEP. It reflects the actual cyclic stretch on alveoli. Lower driving pressure (<15 cmH2O) is associated with better outcomes in ARDS.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-23", type: "question", question: "Enteral nutrition in ARDS should be initiated:", options: ["After 7 days of ICU stay", "Within 24-48 hours of ICU admission if hemodynamically stable", "Only after extubation", "Via TPN initially"], correctIndex: 1, answer: "Early enteral nutrition (within 24-48 hours) maintains gut integrity, prevents bacterial translocation, and provides nutritional support. Trophic feeding (10-20 mL/hr) is initiated even in prone position.", category: "Respiratory", difficulty: 2 },
  { id: "rn-ards-24", type: "question", question: "A-a gradient is elevated in ARDS because:", options: ["The patient is hyperventilating", "Damaged alveolar-capillary membrane impairs gas exchange, creating a difference between alveolar and arterial oxygen", "The patient is breathing room air", "FiO2 is too high"], correctIndex: 1, answer: "The A-a gradient (alveolar-arterial O2 difference) is elevated in ARDS because the damaged alveolar-capillary membrane impairs O2 transfer from alveoli to blood. Normal A-a gradient is <10 in young adults.", category: "Respiratory", difficulty: 3 },
  { id: "rn-ards-25", type: "question", question: "Biotrauma in ARDS refers to:", options: ["Physical trauma to the chest wall", "Release of inflammatory mediators from mechanically ventilated injured lung into systemic circulation", "Barotrauma from high pressures", "Trauma from chest tube insertion"], correctIndex: 1, answer: "Biotrauma: mechanical ventilation of injured lungs releases inflammatory cytokines (IL-6, IL-8, TNF-alpha) into the systemic circulation, contributing to multi-organ dysfunction. Lung-protective ventilation minimizes biotrauma.", category: "Respiratory", difficulty: 3 },

  // ============================================================
  // COPD (15 more = 25 total)
  // ============================================================
  { id: "rn-copd-11", type: "question", question: "What is the Reid index and its significance in chronic bronchitis?", options: ["Ratio of FEV1 to FVC", "Ratio of bronchial gland thickness to bronchial wall thickness; >50% indicates chronic bronchitis", "Measurement of air trapping", "Assessment of gas exchange"], correctIndex: 1, answer: "Reid index = mucous gland layer thickness / total bronchial wall thickness. Normal <40%. A ratio >50% indicates mucous gland hypertrophy characteristic of chronic bronchitis.", category: "Respiratory", difficulty: 3 },
  { id: "rn-copd-12", type: "question", question: "GOLD Group E (exacerbator phenotype) in COPD is treated with:", options: ["SABA alone", "LABA + LAMA combination; add ICS if eosinophils >300", "Corticosteroids only", "Antibiotics prophylactically"], correctIndex: 1, answer: "GOLD Group E (frequent exacerbations, >=2/year or >=1 requiring hospitalization) requires LABA + LAMA dual bronchodilation. ICS is added only if blood eosinophils >300 cells/mcL.", category: "Respiratory", difficulty: 3 },
  { id: "rn-copd-13", type: "question", question: "Centrilobular emphysema (most common) predominantly affects which lung zones?", options: ["Lower lobes", "Upper lobes (characteristic of smoking-related emphysema)", "Middle lobes only", "Peripheral lung zones"], correctIndex: 1, answer: "Centrilobular emphysema from smoking predominantly affects the upper lobes. Panacinar emphysema from alpha-1 antitrypsin deficiency predominantly affects the lower lobes.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-14", type: "question", question: "Roflumilast (Daliresp) requires monitoring for:", options: ["Hepatotoxicity", "Weight loss and psychiatric symptoms (depression, suicidal ideation)", "Renal failure", "Hearing loss"], correctIndex: 1, answer: "Roflumilast (PDE4 inhibitor) can cause significant weight loss, diarrhea, and psychiatric effects including depression and suicidal ideation. Monitor mental health and weight regularly.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-15", type: "question", question: "BiPAP in acute COPD exacerbation with respiratory acidosis (pH 7.25-7.35) reduces:", options: ["Mortality only", "Intubation rate by approximately 50%", "The need for antibiotics", "Length of stay only"], correctIndex: 1, answer: "BiPAP for acute COPD exacerbation with respiratory acidosis (pH 7.25-7.35) reduces intubation rates by ~50% and reduces ICU mortality. It is contraindicated in unresponsive patients.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-16", type: "question", question: "What CBC finding is expected in chronic COPD with hypoxemia?", options: ["Leukocytosis", "Polycythemia (elevated hematocrit) from chronic hypoxemia-driven erythropoietin release", "Thrombocytopenia", "Anemia"], correctIndex: 1, answer: "Chronic hypoxemia stimulates erythropoietin release from the kidneys, increasing RBC production (compensatory erythrocytosis). This raises hematocrit and can increase blood viscosity.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-17", type: "question", question: "How many pack-years of smoking are needed to significantly increase COPD risk?", options: ["1-5 pack-years", "5-10 pack-years", ">=10-20 pack-years (risk increases proportionally)", "Only 1 cigarette per day"], correctIndex: 2, answer: "COPD risk significantly increases with >=10-20 pack-years of smoking. Pack-years = (packs per day) × (years smoked). Risk is dose-dependent; higher pack-years = greater severity.", category: "Respiratory", difficulty: 1 },
  { id: "rn-copd-18", type: "question", question: "What vaccinations are recommended for all COPD patients?", options: ["Hepatitis B only", "Annual influenza and pneumococcal (PCV20 or PCV15 + PPSV23) vaccines", "COVID-19 only", "No vaccinations needed"], correctIndex: 1, answer: "All COPD patients should receive annual influenza vaccination and pneumococcal vaccination (PCV20 or PCV15 followed by PPSV23). COVID-19, Tdap, and shingles vaccines are also recommended per age guidelines.", category: "Respiratory", difficulty: 1 },
  { id: "rn-copd-19", type: "question", question: "A COPD patient is prescribed albuterol AND ipratropium nebulizer (DuoNeb). These two drugs work by:", options: ["The same mechanism", "Different mechanisms: albuterol relaxes smooth muscle via beta-2 receptors; ipratropium blocks parasympathetic bronchoconstriction", "Reducing inflammation", "Thinning mucus"], correctIndex: 1, answer: "Albuterol (SABA) stimulates beta-2 receptors for bronchodilation. Ipratropium (SAMA) blocks muscarinic M3 receptors. Together they provide additive bronchodilation through complementary pathways.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-20", type: "question", question: "Long-term oxygen therapy in COPD (PaO2 <55 or SpO2 <88%) has been shown to:", options: ["Cure COPD", "Improve survival when used >=15 hours/day", "Reverse emphysema", "Reduce need for inhalers"], correctIndex: 1, answer: "The NOTT and MRC trials demonstrated that continuous supplemental O2 (>=15 hours/day) improves survival in COPD patients with chronic hypoxemia (PaO2 <55 or SpO2 <88% at rest).", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-21", type: "question", question: "Pulmonary rehabilitation in COPD includes:", options: ["Medication management only", "Supervised exercise training, education, self-management, and psychosocial support", "Surgical intervention", "Continuous oxygen only"], correctIndex: 1, answer: "Pulmonary rehabilitation is a comprehensive program: supervised exercise training (aerobic + strength), education, nutrition counseling, breathing techniques, and psychosocial support. It improves quality of life and reduces dyspnea.", category: "Respiratory", difficulty: 1 },
  { id: "rn-copd-22", type: "question", question: "What is the clinical definition of chronic bronchitis?", options: ["Any cough lasting more than 1 week", "Productive cough for at least 3 months per year for 2 consecutive years", "Chronic nonproductive cough", "Recurrent pneumonia"], correctIndex: 1, answer: "Chronic bronchitis is defined clinically as a productive cough for at least 3 months per year for at least 2 consecutive years, in the absence of other causes. It is a pathological, not radiographic, diagnosis.", category: "Respiratory", difficulty: 1 },
  { id: "rn-copd-23", type: "question", question: "Inhaled corticosteroids in COPD increase the risk of:", options: ["Renal failure", "Pneumonia (especially fluticasone)", "Diabetes mellitus", "Heart failure"], correctIndex: 1, answer: "ICS use in COPD increases pneumonia risk, particularly fluticasone. ICS should only be added for patients with frequent exacerbations AND eosinophils >300. The benefit must outweigh the pneumonia risk.", category: "Respiratory", difficulty: 2 },
  { id: "rn-copd-24", type: "question", question: "Energy conservation techniques for COPD patients include:", options: ["Exercising vigorously to build endurance", "Pacing activities, using assistive devices, and sitting for tasks when possible", "Avoiding all physical activity", "Only exercising in the morning"], correctIndex: 1, answer: "Energy conservation: pace activities with rest periods, use a shower chair, sit when possible (cooking, dressing), use a rolling cart, organize home to minimize trips, and avoid arm elevation above shoulder level.", category: "Respiratory", difficulty: 1 },
  { id: "rn-copd-25", type: "question", question: "What is the significance of FEV1 42% predicted in COPD?", options: ["Normal lung function", "GOLD Stage III - Severe (FEV1 30-49% predicted)", "Mild obstruction", "Very severe obstruction"], correctIndex: 1, answer: "GOLD staging by FEV1 % predicted: Stage I >=80% (mild), Stage II 50-79% (moderate), Stage III 30-49% (severe), Stage IV <30% (very severe). FEV1 42% falls in Stage III - Severe.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // ASTHMA (15 more = 25 total)
  // ============================================================
  { id: "rn-asth-11", type: "question", question: "The early-phase asthma response (minutes after exposure) is primarily mediated by:", options: ["T lymphocytes", "Mast cell degranulation releasing histamine and leukotrienes", "Eosinophils", "Neutrophils"], correctIndex: 1, answer: "Early phase (minutes): allergen cross-links IgE on mast cells → degranulation → histamine (vasodilation, bronchoconstriction) + leukotrienes (potent bronchoconstriction). This causes immediate bronchospasm.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-12", type: "question", question: "The late-phase asthma response (4-8 hours) is characterized by:", options: ["Immediate bronchospasm", "Eosinophil and T-helper 2 lymphocyte infiltration causing sustained inflammation", "Resolution of symptoms", "Mucus clearing"], correctIndex: 1, answer: "Late phase (4-8 hours): eosinophils, Th2 cells, and basophils infiltrate airways. Eosinophils release major basic protein (MBP), which is directly toxic to airway epithelium, causing prolonged inflammation.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-13", type: "question", question: "A patient has asthma, allergic rhinitis, and atopic dermatitis. This is called:", options: ["Reactive airway disease", "The atopic triad - strongest predictor of asthma persistence", "COPD overlap syndrome", "Exercise-induced bronchospasm"], correctIndex: 1, answer: "The atopic triad (asthma + allergic rhinitis + atopic dermatitis) indicates strong atopic predisposition and is the strongest predictor of asthma persistence into adulthood.", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-14", type: "question", question: "Leukotrienes in asthma are approximately how much more potent as bronchoconstrictors than histamine?", options: ["Equal potency", "10 times more potent", "100 times more potent", "1000 times more potent"], correctIndex: 3, answer: "Cysteinyl leukotrienes (LTC4, LTD4, LTE4) are approximately 1000 times more potent than histamine as bronchoconstrictors. This explains why leukotriene modifiers are effective controller medications.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-15", type: "question", question: "Biologic therapy omalizumab (Xolair) treats severe allergic asthma by:", options: ["Blocking histamine receptors", "Binding free IgE antibodies, preventing mast cell activation", "Killing eosinophils", "Relaxing bronchial smooth muscle"], correctIndex: 1, answer: "Omalizumab is an anti-IgE monoclonal antibody that binds circulating IgE, preventing it from attaching to mast cells and basophils. This reduces allergic inflammation in severe allergic (IgE-mediated) asthma.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-16", type: "question", question: "Which peak flow value indicates a severe asthma attack requiring emergency intervention?", options: [">80% personal best", "50-80% personal best", "<50% personal best (RED zone)", "Any value above 200 L/min"], correctIndex: 2, answer: "PEF <50% personal best = RED zone (emergency). PEF 50-80% = YELLOW zone (caution, step up therapy). PEF >80% = GREEN zone (well-controlled). This is the basis of asthma action plans.", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-17", type: "question", question: "An MDI (metered-dose inhaler) should be used with a spacer because:", options: ["It makes the inhaler louder", "A spacer allows medication particles to slow down and distribute more evenly, increasing lung deposition", "It is required by law", "Spacers contain additional medication"], correctIndex: 1, answer: "Spacers hold the aerosolized medication in a chamber, allowing the propellant to evaporate and particles to slow down. This increases lung deposition from ~10% to ~20% and reduces oral/throat deposition (fewer side effects).", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-18", type: "question", question: "Exercise-induced bronchoconstriction (EIB) can be prevented by:", options: ["Avoiding all exercise", "Using a SABA 15-20 minutes before exercise or using montelukast daily", "Using antibiotics before exercise", "Drinking cold water"], correctIndex: 1, answer: "EIB prevention: SABA (albuterol) 15-20 minutes before exercise provides 2-4 hours of protection. Daily montelukast is effective for frequent EIB. Warming up gradually also helps.", category: "Respiratory", difficulty: 1 },
  { id: "rn-asth-19", type: "question", question: "Airway remodeling in chronic asthma involves:", options: ["Reversible bronchospasm only", "Subepithelial fibrosis, smooth muscle hypertrophy, mucous gland hyperplasia, and angiogenesis", "Normal tissue repair", "Only mucus production changes"], correctIndex: 1, answer: "Chronic airway inflammation leads to structural remodeling: subepithelial fibrosis (basement membrane thickening), smooth muscle hypertrophy, goblet cell/mucous gland hyperplasia, and new blood vessel formation. These changes are IRREVERSIBLE.", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-20", type: "question", question: "In status asthmaticus, systemic corticosteroids should be administered:", options: ["Only after 24 hours of bronchodilator therapy", "Early (within the first hour) to reduce airway inflammation", "Only if the patient requires intubation", "After discharge from the ED"], correctIndex: 1, answer: "Systemic corticosteroids (IV methylprednisolone or oral prednisone) should be given early in severe exacerbation. They take 4-6 hours for full effect, so early administration is crucial.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-21", type: "question", question: "Nighttime and early morning asthma symptoms are worst because:", options: ["Allergen exposure is highest", "Circadian cortisol levels are lowest at night, reducing anti-inflammatory protection and increasing airway reactivity", "Room temperature drops", "Humidity increases"], correctIndex: 1, answer: "Asthma symptoms peak at night/early morning due to circadian cortisol nadir (lowest anti-inflammatory protection), increased vagal tone (parasympathetic bronchoconstriction), and supine position effects.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-22", type: "question", question: "GERD worsens asthma by:", options: ["Causing pneumonia", "Microaspiration of gastric acid and vagal nerve-mediated reflex bronchoconstriction", "Increasing mucus production only", "No relationship exists"], correctIndex: 1, answer: "GERD triggers asthma through: (1) microaspiration of gastric acid into airways causing direct irritation, and (2) vagal nerve-mediated reflex bronchoconstriction when acid contacts the distal esophagus.", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-23", type: "question", question: "Which asthma step requires referral for biologic therapy?", options: ["Step 1", "Step 2", "Step 3", "Step 5 (severe uncontrolled asthma on high-dose ICS-LABA)"], correctIndex: 3, answer: "GINA Step 5: high-dose ICS-LABA with persistent symptoms. Referral for phenotyping (allergic vs eosinophilic) and biologic therapy: omalizumab (anti-IgE), mepolizumab/benralizumab (anti-IL-5), dupilumab (anti-IL-4/13).", category: "Respiratory", difficulty: 3 },
  { id: "rn-asth-24", type: "question", question: "An asthma patient on a LABA (salmeterol) must also be on:", options: ["An antibiotic", "An inhaled corticosteroid (ICS) - LABA should never be used alone in asthma", "A leukotriene modifier", "An oral corticosteroid"], correctIndex: 1, answer: "In asthma, LABAs must ALWAYS be used with an ICS. LABA monotherapy in asthma increases severe exacerbations and asthma-related deaths (FDA boxed warning removed when used with ICS).", category: "Respiratory", difficulty: 2 },
  { id: "rn-asth-25", type: "question", question: "Ipratropium in acute asthma is used:", options: ["As monotherapy for maintenance", "Combined WITH albuterol in acute exacerbation for additive bronchodilation", "As a substitute for corticosteroids", "Only for COPD patients"], correctIndex: 1, answer: "Ipratropium is added to albuterol in acute asthma exacerbation for additive bronchodilation. It blocks parasympathetic-mediated bronchoconstriction. Used in combination only - not for maintenance.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // PE (15 more = 25 total)
  // ============================================================
  { id: "rn-pe-11", type: "question", question: "What is the Wells criteria used for?", options: ["Diagnosing heart failure", "Estimating clinical probability of PE before testing", "Staging cancer", "Assessing fall risk"], correctIndex: 1, answer: "Wells criteria assigns points for clinical features (DVT signs, tachycardia, immobilization, hemoptysis, malignancy, prior DVT/PE) to categorize PE probability as low, moderate, or high. This guides further testing.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-12", type: "question", question: "A submassive PE is defined as:", options: ["Any small PE", "PE with RV dysfunction but without systemic hypotension (SBP >90)", "PE in a young patient", "PE without DVT"], correctIndex: 1, answer: "Submassive PE: evidence of RV dysfunction (echo findings, elevated troponin/BNP) but maintained systemic BP (SBP >90). Consider catheter-directed therapy; systemic thrombolysis is debated.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-13", type: "question", question: "Factor V Leiden is the most common inherited thrombophilia. It causes PE risk by:", options: ["Increasing platelet count", "Creating resistance to activated protein C, impairing natural anticoagulation", "Increasing fibrinogen levels", "Causing endothelial injury"], correctIndex: 1, answer: "Factor V Leiden mutation makes factor V resistant to inactivation by activated protein C, a natural anticoagulant. This creates a persistent hypercoagulable state and increases DVT/PE risk 3-8 fold.", category: "Respiratory", difficulty: 3 },
  { id: "rn-pe-14", type: "question", question: "Why should fluids be given cautiously in massive PE?", options: ["Risk of pulmonary edema", "Excessive fluid overloads the already failing right ventricle, worsening RV dilation and LV compression", "Risk of dilutional anemia", "No fluid is needed"], correctIndex: 1, answer: "In massive PE, the RV is already dilated and failing. Excessive fluid further dilates the RV, bowing the septum into the LV and reducing cardiac output. Small cautious fluid boluses (250-500mL) with vasopressor support is preferred.", category: "Respiratory", difficulty: 3 },
  { id: "rn-pe-15", type: "question", question: "What is the minimum duration of anticoagulation for a provoked PE (known trigger)?", options: ["2 weeks", "3 months", "6 months", "Lifelong"], correctIndex: 1, answer: "Provoked PE (identifiable trigger like surgery, immobilization): minimum 3 months anticoagulation. Unprovoked or recurrent PE: consider indefinite anticoagulation based on bleeding risk assessment.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-16", type: "question", question: "Post-PE syndrome affects approximately what percentage of PE survivors?", options: ["5%", "10-15%", "30-50% may have persistent symptoms (dyspnea, exercise intolerance)", "Nearly 100%"], correctIndex: 2, answer: "Post-PE syndrome: 30-50% of PE survivors experience persistent dyspnea, exercise intolerance, or reduced quality of life months after the event. Some develop chronic thromboembolic PH (CTEPH).", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-17", type: "question", question: "ABG findings in PE typically show:", options: ["Metabolic acidosis", "Respiratory alkalosis (hyperventilation), hypoxemia, and increased A-a gradient", "Respiratory acidosis", "Normal values"], correctIndex: 1, answer: "PE causes respiratory alkalosis (hyperventilation from dyspnea/anxiety), hypoxemia (V/Q mismatch - dead space ventilation), and increased A-a gradient. Normal ABG does not exclude PE.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-18", type: "question", question: "Heparin-induced thrombocytopenia (HIT) paradoxically causes:", options: ["Bleeding", "Thrombosis (clots, not bleeding) despite low platelets", "Anemia", "Leukopenia"], correctIndex: 1, answer: "HIT: antibodies against heparin-PF4 complexes activate platelets, causing paradoxical thrombosis. Patients develop new DVT, PE, or arterial thrombi. Stop heparin immediately and start argatroban or bivalirudin.", category: "Respiratory", difficulty: 3 },
  { id: "rn-pe-19", type: "question", question: "SCDs (sequential compression devices) prevent DVT/PE by:", options: ["Thinning the blood", "Mechanically mimicking calf muscle pump action to prevent venous stasis", "Reducing inflammation", "Increasing cardiac output"], correctIndex: 1, answer: "SCDs sequentially compress the legs from distal to proximal, mimicking the calf muscle pump. This prevents venous stasis (Virchow triad component), promotes venous return, and stimulates fibrinolysis.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pe-20", type: "question", question: "When transitioning from heparin to warfarin for PE, both drugs are given together for:", options: ["1 day", "At least 5 days AND until INR is therapeutic (2.0-3.0) for at least 24 hours", "2 weeks", "No overlap is needed"], correctIndex: 1, answer: "Warfarin takes 5-7 days to reach full anticoagulant effect. It initially creates a transient hypercoagulable state (protein C/S depleted before clotting factors). Overlap with heparin for >=5 days and INR 2.0-3.0 for >=24h.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-21", type: "question", question: "Rivaroxaban and apixaban can be used as single-drug therapy for PE because:", options: ["They are more potent than heparin", "They do not require heparin bridging - oral-only approach with loading dose", "They work on the same target as heparin", "They are cheaper"], correctIndex: 1, answer: "Rivaroxaban (15mg BID x 21 days then 20mg daily) and apixaban (10mg BID x 7 days then 5mg BID) have built-in loading doses, eliminating the need for initial injectable anticoagulation.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-22", type: "question", question: "Trousseau syndrome (migratory thrombophlebitis) is associated with:", options: ["Diabetes", "Occult malignancy - recurrent DVTs in unusual locations may be the first sign of cancer", "Pregnancy", "Autoimmune disease"], correctIndex: 1, answer: "Trousseau syndrome: recurrent migratory superficial thrombophlebitis associated with occult malignancy (especially pancreatic, lung, GI cancers). Cancer creates a hypercoagulable state through multiple mechanisms.", category: "Respiratory", difficulty: 3 },
  { id: "rn-pe-23", type: "question", question: "Early ambulation after surgery prevents PE primarily by addressing which Virchow triad element?", options: ["Hypercoagulability", "Endothelial injury", "Venous stasis", "All three equally"], correctIndex: 2, answer: "Early ambulation directly addresses venous stasis by activating the calf muscle pump, promoting venous return, and preventing blood pooling in the deep veins. This is the most modifiable risk factor post-surgery.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pe-24", type: "question", question: "For PE in pregnancy, which anticoagulant is safe to use?", options: ["Warfarin (safe throughout pregnancy)", "LMWH (enoxaparin) - does not cross the placenta", "Rivaroxaban (DOAC)", "Aspirin only"], correctIndex: 1, answer: "LMWH (enoxaparin) is the anticoagulant of choice in pregnancy - it does not cross the placenta and is not teratogenic. Warfarin crosses the placenta and is teratogenic (Category X). DOACs lack safety data in pregnancy.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pe-25", type: "question", question: "What is the gold standard imaging for PE diagnosis?", options: ["Chest X-ray", "V/Q scan", "CT pulmonary angiography (CTPA)", "Echocardiogram"], correctIndex: 2, answer: "CTPA is the gold standard imaging for PE. It directly visualizes thrombus in the pulmonary arteries with high sensitivity and specificity. V/Q scan is used when CTPA is contraindicated.", category: "Respiratory", difficulty: 1 },

  // ============================================================
  // PNEUMONIA (15 more = 25 total)
  // ============================================================
  { id: "rn-pna-11", type: "question", question: "Procalcitonin helps distinguish:", options: ["Viral from fungal pneumonia", "Bacterial (elevated) from viral (low/normal) pneumonia", "Typical from atypical pneumonia", "Pneumonia from ARDS"], correctIndex: 1, answer: "Procalcitonin is significantly elevated in bacterial infections (>0.25 mcg/L) but remains low/normal in viral infections. It helps guide antibiotic decisions and duration of therapy.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-12", type: "question", question: "Legionella pneumonia is diagnosed by:", options: ["Blood culture", "Urinary antigen test (rapid detection)", "Sputum Gram stain only", "Chest X-ray pattern"], correctIndex: 1, answer: "Legionella urinary antigen test provides rapid diagnosis (sensitivity ~75% for serogroup 1). Legionella is an atypical organism that does not grow on standard cultures. It is associated with water systems (cooling towers, whirlpools).", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-13", type: "question", question: "Aspiration pneumonia typically involves which lung segments?", options: ["Upper lobes bilaterally", "Right lower lobe and posterior segments (when supine) due to anatomy of right mainstem bronchus", "Left upper lobe", "Both middle lobes"], correctIndex: 1, answer: "The right mainstem bronchus is wider, shorter, and more vertical than the left, making aspirated material more likely to enter the right lung. Supine aspiration affects posterior segments; upright aspiration affects lower lobes.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-14", type: "question", question: "Atypical pneumonia (walking pneumonia) is characterized by:", options: ["High fever and lobar consolidation", "Gradual onset, dry cough, extrapulmonary symptoms, and interstitial infiltrates", "Productive cough with rust-colored sputum", "Cavitary lesions on CXR"], correctIndex: 1, answer: "Atypical pneumonia (Mycoplasma, Chlamydophila, Legionella): gradual onset, nonproductive cough, headache, myalgias, GI symptoms, interstitial/diffuse infiltrates on CXR. Mycoplasma is most common in young adults.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-15", type: "question", question: "What is the most common cause of healthcare-associated pneumonia requiring MRSA coverage?", options: ["Streptococcus pneumoniae", "Staphylococcus aureus (MRSA) in patients with recent hospitalization or MRSA risk factors", "Mycoplasma pneumoniae", "Haemophilus influenzae"], correctIndex: 1, answer: "MRSA is a major HAP/VAP pathogen, particularly in patients with prior MRSA colonization, recent hospitalization, or broad-spectrum antibiotic use. Coverage with vancomycin or linezolid is added to the HAP regimen.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-16", type: "question", question: "What nursing intervention is MOST important before starting antibiotics for pneumonia?", options: ["Obtain a chest X-ray", "Obtain sputum and blood cultures before the first antibiotic dose", "Start IV fluids", "Apply oxygen"], correctIndex: 1, answer: "Cultures obtained before antibiotics yield more accurate pathogen identification. However, culture collection should NOT delay antibiotic administration beyond 1 hour if sepsis is suspected.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-17", type: "question", question: "C. difficile infection is a common complication of antibiotic therapy for pneumonia. The nurse monitors for:", options: ["Constipation", "Watery diarrhea (≥3 loose stools/day), abdominal pain, and fever", "Hemoptysis", "Urinary retention"], correctIndex: 1, answer: "C. difficile: antibiotic-associated diarrhea caused by disruption of normal gut flora. Watch for >=3 watery stools/day, abdominal pain/cramping, fever, and leukocytosis. Contact precautions required.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pna-18", type: "question", question: "Incentive spirometry for pneumonia prevention involves:", options: ["5 deep breaths every 4 hours", "10 sustained maximal inspirations every 1-2 hours while awake", "Continuous use while sleeping", "Using it only when coughing"], correctIndex: 1, answer: "Incentive spirometry: 10 sustained maximal inspiratory efforts every 1-2 hours while awake. It prevents atelectasis by promoting alveolar expansion and encouraging coughing to clear secretions.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pna-19", type: "question", question: "Levofloxacin is avoided in patients with myasthenia gravis because:", options: ["It causes hepatotoxicity", "Fluoroquinolones exacerbate neuromuscular weakness and can cause respiratory failure", "It interacts with pyridostigmine", "No specific concern"], correctIndex: 1, answer: "Fluoroquinolones can worsen neuromuscular junction weakness in myasthenia gravis, potentially causing life-threatening respiratory failure. They are contraindicated in MG patients.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-20", type: "question", question: "Empyema as a pneumonia complication is characterized by:", options: ["Air in the pleural space", "Purulent fluid in the pleural space requiring drainage (chest tube or thoracoscopic surgery)", "Blood in the pleural space", "Normal pleural fluid"], correctIndex: 1, answer: "Empyema = infected (purulent) fluid in the pleural space, a serious pneumonia complication. Diagnosed by thoracentesis showing purulent fluid, positive Gram stain/culture, or pH <7.2. Requires chest tube drainage.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-21", type: "question", question: "A patient with pneumonia has SpO2 88% on room air. What supplemental oxygen device should be applied first?", options: ["Venturi mask at 24%", "Nasal cannula at 2-4 L/min to target SpO2 >92%", "Non-rebreather mask at 15 L/min", "No oxygen needed"], correctIndex: 1, answer: "For moderate hypoxemia (SpO2 88%), start with nasal cannula at 2-4 L/min titrated to SpO2 >92% (>88% in COPD). Escalate to simple mask or high-flow if inadequate response.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pna-22", type: "question", question: "The nurse should position a patient with left-sided pneumonia:", options: ["Left side down (affected side down) to improve perfusion to the good lung", "Right side down (good lung down) to maximize V/Q matching", "Flat on their back", "Prone at all times"], correctIndex: 1, answer: "Position with the GOOD lung (unaffected side) DOWN. Gravity directs more blood flow to the dependent (down) lung, which has better ventilation, optimizing V/Q matching and oxygenation.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-23", type: "question", question: "Which patient population is most at risk for Pseudomonas pneumonia?", options: ["Healthy young adults", "Patients with bronchiectasis, cystic fibrosis, or prolonged ICU stay", "Children in daycare", "Elderly in nursing homes (usually S. pneumoniae)"], correctIndex: 1, answer: "Pseudomonas aeruginosa pneumonia: risk factors include bronchiectasis, cystic fibrosis, prolonged ICU/ventilator time, immunosuppression, and chronic broad-spectrum antibiotic use. Requires anti-pseudomonal coverage.", category: "Respiratory", difficulty: 2 },
  { id: "rn-pna-24", type: "question", question: "What discharge teaching is essential for a pneumonia patient?", options: ["Stop antibiotics when symptoms improve", "Complete the full antibiotic course even if feeling better; follow up CXR in 6-8 weeks", "No follow-up needed after discharge", "Avoid all physical activity for 6 months"], correctIndex: 1, answer: "Complete the full antibiotic course to prevent relapse and resistance. Follow-up CXR at 6-8 weeks confirms resolution (important in smokers >50 to rule out underlying malignancy). Vaccinate at discharge.", category: "Respiratory", difficulty: 1 },
  { id: "rn-pna-25", type: "question", question: "Pneumococcal urinary antigen test advantages include:", options: ["It is 100% sensitive", "Rapid results, remains positive even after antibiotic initiation", "It identifies antibiotic susceptibility", "It detects all pneumonia pathogens"], correctIndex: 1, answer: "Pneumococcal urinary antigen: rapid (15 min), positive even after antibiotics have been started (unlike cultures). Detects S. pneumoniae cell wall antigen. Sensitivity ~80%, specificity ~90%.", category: "Respiratory", difficulty: 2 },

  // ============================================================
  // AKI (15 more = 25 total)
  // ============================================================
  { id: "rn-aki-11", type: "question", question: "KDIGO staging for AKI Stage 3 criteria include:", options: ["Creatinine rise 0.3 mg/dL", "Creatinine >=3x baseline OR >=4.0 mg/dL OR initiation of RRT OR UO <0.3 mL/kg/hr for >=24h", "Any creatinine elevation", "BUN >50 mg/dL"], correctIndex: 1, answer: "KDIGO Stage 3 (severe): creatinine >=3x baseline, or >=4.0 mg/dL with acute rise >=0.5, or initiation of RRT, or anuria for >=12 hours, or UO <0.3 mL/kg/hr for >=24 hours.", category: "Renal", difficulty: 3 },
  { id: "rn-aki-12", type: "question", question: "The nurse holds metformin in a patient with AKI because:", options: ["It causes hyperglycemia", "Risk of life-threatening lactic acidosis when the drug accumulates in renal failure", "It worsens hyperkalemia", "It interacts with dialysis"], correctIndex: 1, answer: "Metformin is renally cleared. In AKI, it accumulates and inhibits mitochondrial complex I, promoting anaerobic metabolism and severe lactic acidosis (mortality up to 50%).", category: "Renal", difficulty: 2 },
  { id: "rn-aki-13", type: "question", question: "Post-obstructive diuresis occurs after relieving postrenal AKI. The nurse monitors for:", options: ["Oliguria", "Massive polyuria (urine output >200 mL/hr) with risk of dehydration and electrolyte depletion", "Hematuria only", "Proteinuria"], correctIndex: 1, answer: "After relieving obstruction, the kidneys may produce massive volumes of dilute urine (post-obstructive diuresis). Replace fluids and electrolytes to prevent dehydration and hemodynamic instability.", category: "Renal", difficulty: 3 },
  { id: "rn-aki-14", type: "question", question: "Aminoglycoside (gentamicin) nephrotoxicity is monitored by:", options: ["Liver function tests", "Trough levels before the next dose; also monitor creatinine and BUN", "Peak levels only", "Urine culture"], correctIndex: 1, answer: "Aminoglycoside trough levels must be monitored (draw immediately before next dose). Elevated troughs indicate accumulation and increased nephrotoxicity risk. Also monitor creatinine, BUN, and signs of ototoxicity.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-15", type: "question", question: "The nurse caring for a patient with AKI and metabolic acidosis expects to see:", options: ["Slow, shallow breathing", "Kussmaul breathing (deep, rapid respirations) as respiratory compensation for the acidosis", "Normal respiratory pattern", "Cheyne-Stokes breathing"], correctIndex: 1, answer: "Metabolic acidosis in AKI triggers respiratory compensation: Kussmaul breathing (deep, rapid) blows off CO2 to raise pH. This breathing pattern should NOT be suppressed as it is compensatory.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-16", type: "question", question: "Postrenal AKI is most commonly caused by:", options: ["Kidney stones (bilateral)", "BPH causing bilateral ureteral obstruction or bladder outlet obstruction", "Heart failure", "Sepsis"], correctIndex: 1, answer: "BPH is the most common cause of postrenal AKI in men. Bladder outlet obstruction causes bilateral hydronephrosis. Simple Foley catheter placement may immediately relieve the obstruction and restore urine flow.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-17", type: "question", question: "In prerenal AKI, what happens when IV fluids are administered?", options: ["No change occurs", "Urine output improves rapidly as renal perfusion is restored (the kidney is intact but underperfused)", "Creatinine rises further", "The patient develops pulmonary edema"], correctIndex: 1, answer: "Prerenal AKI = structurally intact kidney with inadequate perfusion. Restoring perfusion with IV fluids rapidly improves urine output and creatinine begins to decline. This response confirms prerenal etiology.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-18", type: "question", question: "What is the nurse's priority assessment for a patient with a new Foley catheter and improving AKI?", options: ["Monitor catheter drainage color only", "Monitor urine output hourly - report <0.5 mL/kg/hr or sudden cessation (obstruction)", "Check catheter size", "Assess for catheter discomfort only"], correctIndex: 1, answer: "Hourly urine output monitoring is critical in AKI. Report output <0.5 mL/kg/hr (ongoing AKI) or sudden cessation (catheter obstruction, clot). Assess urine color, clarity, and presence of sediment.", category: "Renal", difficulty: 1 },
  { id: "rn-aki-19", type: "question", question: "Contrast-induced nephropathy can be prevented by:", options: ["Giving the contrast slowly", "Pre-procedure IV hydration with NS or isotonic bicarbonate; using lowest contrast volume possible", "Administering antihistamines", "No prevention strategy exists"], correctIndex: 1, answer: "CIN prevention: IV hydration before and after contrast (NS or isotonic bicarbonate), use lowest effective contrast volume, use iso-osmolar contrast agents, hold metformin and NSAIDs.", category: "Renal", difficulty: 2 },
  { id: "rn-aki-20", type: "question", question: "Acute interstitial nephritis (AIN) as a cause of intrarenal AKI is suggested by:", options: ["Muddy brown casts", "Fever, rash, eosinophilia, and eosinophils in urine (drug hypersensitivity reaction)", "Massive proteinuria", "BUN/Cr ratio >25:1"], correctIndex: 1, answer: "AIN triad: fever, maculopapular rash, and eosinophilia. It is an allergic/hypersensitivity reaction to drugs (NSAIDs, penicillins, cephalosporins, PPIs). WBC casts and eosinophiluria are characteristic.", category: "Renal", difficulty: 3 },

  // ============================================================
  // CKD (15 more = 25 total)
  // ============================================================
  { id: "rn-ckd-11", type: "question", question: "Restless leg syndrome in CKD is caused by:", options: ["Hypercalcemia", "Uremic toxin accumulation and iron deficiency", "Hypertension", "Medication side effects only"], correctIndex: 1, answer: "RLS in CKD results from uremic toxin effects on the nervous system, iron deficiency (common in CKD), and dopaminergic dysfunction. It worsens at rest and is relieved by movement. Dialysis may improve symptoms.", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-12", type: "question", question: "The preferred phosphate binder over calcium-based binders in CKD is:", options: ["Calcium carbonate (always preferred)", "Sevelamer (Renagel/Renvela) - avoids additional calcium load and vascular calcification", "Aluminum hydroxide", "Magnesium hydroxide"], correctIndex: 1, answer: "Sevelamer is preferred because calcium-based binders can cause hypercalcemia and accelerate vascular calcification. Aluminum-based binders cause aluminum toxicity with long-term use. Sevelamer is non-calcium, non-aluminum.", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-13", type: "question", question: "Uremic pericarditis in ESRD presents with:", options: ["Absent heart sounds", "Pericardial friction rub (scratchy sound heard best with patient leaning forward)", "S3 gallop only", "Muffled heart sounds only (tamponade, not pericarditis)"], correctIndex: 1, answer: "Uremic pericarditis: friction rub (scratchy, grating sound in 3 components) best heard with patient sitting up and leaning forward. It is an indication for urgent dialysis. Avoid anticoagulation (hemorrhagic risk).", category: "Renal", difficulty: 2 },
  { id: "rn-ckd-14", type: "question", question: "GFR <15 mL/min represents what CKD stage?", options: ["Stage 3", "Stage 4", "Stage 5 (kidney failure) - dialysis or transplant indicated", "Stage 2"], correctIndex: 2, answer: "CKD Stage 5 = GFR <15 mL/min = kidney failure/ESRD. Dialysis or kidney transplant is indicated. Symptoms of uremia are usually present at this stage.", category: "Renal", difficulty: 1 },
  { id: "rn-ckd-15", type: "question", question: "Why is anemia in CKD normocytic normochromic?", options: ["Iron deficiency", "Vitamin B12 deficiency", "Erythropoietin deficiency - insufficient stimulus for RBC production, not a nutritional deficiency", "Folate deficiency"], correctIndex: 2, answer: "CKD anemia is from EPO deficiency. RBCs are normal in size (normocytic) and color (normochromic) because the issue is inadequate production, not abnormal hemoglobin synthesis. Iron deficiency may coexist and should be corrected.", category: "Renal", difficulty: 2 },

  // ============================================================
  // ADDITIONAL TOPICS - Glomerulonephritis, Fluid, Na, K, Ca/PO4, Acid-Base (remaining)
  // ============================================================
  { id: "rn-gn-6", type: "question", question: "Nephrotic syndrome increases infection risk because:", options: ["Kidney damage causes immunosuppression", "Massive proteinuria includes loss of immunoglobulins (IgG) in urine", "Steroids used for treatment only", "Edema impairs skin barrier only"], correctIndex: 1, answer: "In nephrotic syndrome, the damaged glomeruli allow immunoglobulins (especially IgG) to pass into urine. This acquired immunodeficiency increases susceptibility to encapsulated organisms (S. pneumoniae).", category: "Renal", difficulty: 2 },
  { id: "rn-gn-7", type: "question", question: "IgA nephropathy differs from post-streptococcal GN in timing: IgA hematuria occurs:", options: ["2-3 weeks after infection", "DURING or immediately after a URI (synpharyngitic)", "Months after infection", "Only with impetigo"], correctIndex: 1, answer: "IgA nephropathy: synpharyngitic hematuria (during/immediately after URI). Post-strep GN: latent period of 1-3 weeks after strep infection. This timing difference is a key differentiating feature.", category: "Renal", difficulty: 2 },
  { id: "rn-fld-6", type: "question", question: "Edema formation from heart failure is caused by:", options: ["Decreased capillary permeability", "Increased capillary hydrostatic pressure from volume overload and venous congestion", "Lymphatic obstruction", "Increased osmotic pressure"], correctIndex: 1, answer: "In HF, poor cardiac output causes fluid retention (RAAS activation) and venous congestion, increasing capillary hydrostatic pressure. Fluid is pushed out of capillaries into interstitial space (Starling forces).", category: "Renal", difficulty: 2 },
  { id: "rn-fld-7", type: "question", question: "25% albumin is used for third-spacing because:", options: ["It replaces lost protein", "It is hyperoncotic - draws fluid from interstitial space INTO the intravascular compartment", "It provides nutrition", "It replaces blood loss"], correctIndex: 1, answer: "25% albumin is hyperoncotic: it raises plasma oncotic pressure, drawing fluid from edematous interstitial tissues back into the intravascular space. Used for third-spacing with hypoalbuminemia.", category: "Renal", difficulty: 2 },
  { id: "rn-na-6", type: "question", question: "Central DI responds to desmopressin but nephrogenic DI does not because:", options: ["Nephrogenic DI has too much ADH", "In nephrogenic DI, the kidneys cannot respond to ADH (receptor or post-receptor defect)", "Desmopressin only works for Na imbalances", "Central DI is more severe"], correctIndex: 1, answer: "Central DI: pituitary does not produce ADH → desmopressin replaces it. Nephrogenic DI: kidneys are resistant to ADH (receptor mutation, lithium, hypercalcemia) → giving more ADH analog does not help.", category: "Renal", difficulty: 2 },
  { id: "rn-na-7", type: "question", question: "A patient with SIADH should have which fluid management approach?", options: ["Aggressive IV hydration", "Fluid restriction (1-1.5 L/day) as first-line treatment", "Hypertonic saline for all patients", "No fluid changes needed"], correctIndex: 1, answer: "Fluid restriction (1-1.5 L/day) is first-line for SIADH. Limiting water intake allows sodium to concentrate. If unsuccessful, demeclocycline or tolvaptan may be added.", category: "Renal", difficulty: 1 },
  { id: "rn-k-6", type: "question", question: "What is the earliest ECG sign of hyperkalemia?", options: ["Widened QRS", "Peaked (tall, narrow) T waves", "Absent P waves", "Sine wave pattern"], correctIndex: 1, answer: "ECG progression of hyperkalemia: peaked T waves (5.5-6.5) → PR prolongation and P wave flattening (6.5-7.5) → widened QRS (7.0-8.0) → sine wave pattern (>8.0) → V-fib/asystole.", category: "Renal", difficulty: 1 },
  { id: "rn-k-7", type: "question", question: "Loop diuretics cause hypokalemia because they:", options: ["Directly excrete potassium", "Block Na-K-2Cl cotransporter in the loop of Henle, increasing K+ delivery to the distal tubule where it is secreted", "Decrease aldosterone", "Block potassium absorption in the gut"], correctIndex: 1, answer: "Loop diuretics inhibit NKCC2 in the thick ascending limb. This increases Na+ delivery to the collecting duct, where Na+ is reabsorbed in exchange for K+ (ENaC/ROMK), increasing K+ excretion.", category: "Renal", difficulty: 3 },
  { id: "rn-ca-6", type: "question", question: "First-line treatment for severe hypercalcemia is:", options: ["Calcitonin", "Aggressive IV normal saline hydration (200-300 mL/hr)", "Bisphosphonate infusion", "Furosemide"], correctIndex: 1, answer: "Aggressive IV NS hydration is FIRST: it dilutes calcium, restores intravascular volume (hypercalcemia causes polyuria/dehydration), and promotes renal calcium excretion. Calcitonin and bisphosphonates are added after hydration.", category: "Renal", difficulty: 2 },
  { id: "rn-ca-7", type: "question", question: "Corrected calcium formula when albumin is low:", options: ["No correction needed", "Corrected Ca = measured Ca + 0.8 × (4.0 - patient's albumin)", "Corrected Ca = measured Ca × albumin", "Corrected Ca = measured Ca - albumin"], correctIndex: 1, answer: "For every 1 g/dL albumin below 4.0, add 0.8 mg/dL to the measured calcium. Example: Ca 7.5, albumin 2.5 → corrected Ca = 7.5 + 0.8(4.0-2.5) = 7.5 + 1.2 = 8.7 mg/dL.", category: "Renal", difficulty: 2 },
  { id: "rn-ab-11", type: "question", question: "The systematic approach to ABG interpretation starts with:", options: ["Calculating anion gap", "Step 1: Assess pH - is the patient acidotic (<7.35) or alkalotic (>7.45)?", "Looking at PaCO2 first", "Assessing bicarbonate first"], correctIndex: 1, answer: "Step 1: pH direction (acidosis vs alkalosis). Step 2: Primary disorder (match pH with CO2 or HCO3). Step 3: Compensation. Step 4: Anion gap if metabolic acidosis. Step 5: Delta-delta. Step 6: Clinical correlation.", category: "Renal", difficulty: 1 },
  { id: "rn-ab-12", type: "question", question: "Contraction alkalosis from diuretics occurs because:", options: ["Diuretics directly produce bicarbonate", "ECF volume contracts, concentrating bicarbonate that becomes relatively more abundant", "Diuretics block acid secretion", "Diuretics increase bicarbonate production"], correctIndex: 1, answer: "Diuresis reduces ECF volume while bicarbonate amount stays relatively constant, increasing its concentration. Additionally, volume depletion activates RAAS, promoting H+ secretion and bicarbonate generation.", category: "Renal", difficulty: 3 },
  { id: "rn-ab-13", type: "question", question: "In a patient compensating for metabolic acidosis with Kussmaul breathing, the nurse should:", options: ["Sedate the patient to slow breathing", "NOT suppress the breathing - it is compensatory and preventing worse acidosis", "Place a rebreather mask", "Encourage slow breathing"], correctIndex: 1, answer: "Kussmaul breathing is the body's compensatory mechanism to blow off CO2 and raise pH. Suppressing it (sedation, intubation without proper settings) would worsen acidosis and potentially cause cardiac arrest.", category: "Renal", difficulty: 2 },
  { id: "rn-ab-14", type: "question", question: "The delta-delta ratio in metabolic acidosis: a value >2 suggests:", options: ["Pure anion gap acidosis", "Concurrent metabolic alkalosis (HCO3 is higher than expected for the AG elevation)", "Concurrent non-anion gap acidosis", "Respiratory compensation"], correctIndex: 1, answer: "Delta-delta >2: HCO3 has not dropped proportionally to the AG rise, meaning something is 'protecting' the bicarbonate - a concurrent metabolic alkalosis (e.g., DKA patient who is also vomiting).", category: "Renal", difficulty: 3 },
  { id: "rn-ab-15", type: "question", question: "Respiratory compensation for metabolic alkalosis is limited because:", options: ["The lungs cannot retain CO2", "The body will NOT hypoventilate to the point of significant hypoxemia", "There is no respiratory compensation for alkalosis", "Compensation occurs only with acidosis"], correctIndex: 1, answer: "Respiratory compensation for metabolic alkalosis (hypoventilation to retain CO2) is self-limited because the resulting hypoxemia stimulates breathing. Expected PaCO2 rarely exceeds 55 mmHg from compensation alone.", category: "Renal", difficulty: 3 },
];
